// Aggregate all data into dashboard report
const gadsData = $('Google Ads - Stats 7 jours').first().json.results || [];
const hsDeals = $('HubSpot - Deals semaine').first().json.results || [];

// === GOOGLE ADS ===
let totalDepense = 0, totalClics = 0, totalConversions = 0;
const campaignsData = [];

for (const r of gadsData) {
  const cout = (r.metrics.costMicros || 0) / 1_000_000;
  const conv = r.metrics.conversions || 0;
  const clics = r.metrics.clicks || 0;
  const cpa = conv > 0 ? cout / conv : null;

  totalDepense += cout;
  totalClics += clics;
  totalConversions += conv;

  campaignsData.push({
    name: r.campaign.name,
    cout: cout,
    conversions: conv,
    cpa: cpa
  });
}

const cpaMoyen = totalConversions > 0 ? totalDepense / totalConversions : null;

// Sort by CPA to find best and worst
const withCpa = campaignsData.filter(c => c.cpa !== null);
withCpa.sort((a, b) => a.cpa - b.cpa);
const bestCpa = withCpa[0] || null;
const worstCpa = withCpa[withCpa.length - 1] || null;

// === HUBSPOT ===
const totalLeads = hsDeals.length;
const dealsCreated = hsDeals.length;
const dealsClosed = hsDeals.filter(d => d.properties?.dealstage === '3422415597').length;
const dealsPerdus = hsDeals.filter(d => d.properties?.dealstage === '3422415598').length;
const devisEnvoyes = hsDeals.filter(d => ['qualifiedtobuy', 'presentationscheduled'].includes(d.properties?.dealstage)).length;

// === WEEK NUMBER ===
const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const weekNum = Math.ceil(((now - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);

const dashboardRow = {
  semaine: `S${weekNum}-${now.getFullYear()}`,
  date: now.toLocaleDateString('fr-FR'),
  depense_ads: totalDepense.toFixed(2),
  clics: totalClics,
  conversions: totalConversions,
  cpa_moyen: cpaMoyen ? cpaMoyen.toFixed(2) : 'N/A',
  leads_total: totalLeads,
  deals_clos: dealsClosed,
  deals_perdus: dealsPerdus,
  devis_envoyes: devisEnvoyes,
  best_campagne: bestCpa ? bestCpa.name : 'N/A',
  best_cpa: bestCpa ? bestCpa.cpa.toFixed(2) : 'N/A',
  worst_campagne: worstCpa ? worstCpa.name : 'N/A',
  worst_cpa: worstCpa ? worstCpa.cpa.toFixed(2) : 'N/A'
};

const telegramMsg = [
  `📊 <b>RAPPORT SEMAINE S${weekNum}/${now.getFullYear()}</b>`,
  ``,
  `💰 <b>Google Ads</b>`,
  `• Dépense : ${totalDepense.toFixed(2)}€`,
  `• Clics : ${totalClics}`,
  `• Conversions : ${totalConversions}`,
  `• CPA moyen : ${cpaMoyen ? cpaMoyen.toFixed(2) + '€' : 'N/A'}`,
  ``,
  `📋 <b>Leads & Deals</b>`,
  `• Nouveaux leads : ${totalLeads}`,
  `• Devis envoyés : ${devisEnvoyes}`,
  `• Deals closés : ${dealsClosed} ✅`,
  `• Deals perdus : ${dealsPerdus} ❌`,
  ``,
  bestCpa ? `🏆 Meilleur CPA : ${bestCpa.name} — ${bestCpa.cpa.toFixed(2)}€` : '',
  worstCpa ? `⚠️ Pire CPA : ${worstCpa.name} — ${worstCpa.cpa.toFixed(2)}€` : ''
].filter(l => l !== '').join('\n');

return [{ json: { dashboardRow, telegramMsg } }];
